final:
module binary_counter(
    input        clk,
    input        reset,
    output [3:0] count
);

reg [3:0] obf_count_reg;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        obf_count_reg <= 4'b0000;
    end else begin
        obf_count_reg <= obf_count_reg + 1;
    end
end

assign count = obf_count_reg;

endmodule
